# Minimal reliability wrapper — verify this pattern exists in the service
import anthropic, time
from anthropic import RateLimitError, APIStatusError

client = anthropic.Anthropic()

def call_with_retry(system: str, user: str, max_attempts: int = 3) -> str:
    for attempt in range(max_attempts):
        try:
            response = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=1024,
                timeout=10.0,          # explicit timeout required
                system=system,
                messages=[{"role": "user", "content": user}],
            )
            return response.content[0].text
        except RateLimitError:
            if attempt == max_attempts - 1: raise
            time.sleep(2 ** attempt)     # 1s, 2s, 4s
        except APIStatusError as e:
            if e.status_code >= 500 and attempt < max_attempts - 1:
                time.sleep(2 ** attempt)
            else:
                raise
    raise RuntimeError("unreachable")

# PRR test: verify no user input reaches the system prompt
import ast, sys
from pathlib import Path

VIOLATION_PATTERN = "system"
SRC = Path("src/")

def check_prompt_injection_risk():
    issues = []
    for py_file in SRC.rglob("*.py"):
        src = py_file.read_text()
        if "messages.create" not in src: continue
        tree = ast.parse(src)
        for node in ast.walk(tree):
            if not isinstance(node, ast.Call): continue
            for kw in node.keywords:
                if kw.arg != "system": continue
                # Flag if system value contains an f-string or .format() call
                if isinstance(kw.value, ast.JoinedStr):
                    issues.append(f"{py_file}:{node.lineno} system= uses f-string (risk: user data in system prompt)")
                if isinstance(kw.value, ast.Call):
                    if isinstance(kw.value.func, ast.Attribute) and kw.value.func.attr == "format":
                        issues.append(f"{py_file}:{node.lineno} system= uses .format() (risk: user data in system prompt)")
    return issues

issues = check_prompt_injection_risk()
for i in issues: print("WARN:", i)
if issues:
    print(f"\n{len(issues)} potential injection risk(s). Review before PRR sign-off.")
    sys.exit(1)
print("No system prompt injection risks detected.")
